/**
 * @name Path traversal in ResourceController to GenericResourceRepository without validation
 * @description User-controlled path from ResourceController reaches GenericResourceRepository.findOne() without proper path validation
 * @kind path-problem
 * @problem.severity error
 * @id java/resource-controller-to-generic-repo
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ResourceControllerConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // HTTP request parameters in ResourceController
    exists(Method m |
      m.getDeclaringType().hasQualifiedName("org.springframework.cloud.config.server.resource", "ResourceController") and
      source.asParameter() = m.getAParameter()
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // findOne call in GenericResourceRepository (takes name arg)
    exists(MethodCall mc |
      mc.getMethod().hasName("findOne") and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.springframework.cloud.config.server.resource", "GenericResourceRepository") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // getResource call in GenericResourceRepository
    exists(MethodCall mc |
      mc.getMethod().hasName("getResource") and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.springframework.framework.core.io", "ResourceLoader") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

