/**
 * @name NativeEnvironmentRepository cleanPath with file: prefix injection risk
 * @description NativeEnvironmentRepository uses cleanPath() which may not prevent file: prefix injection
 * @kind path-problem
 * @problem.severity error
 * @id java/native-env-file-prefix-injection
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module NativeEnvConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Parameters in NativeEnvironmentRepository methods
    exists(Method m |
      m.getDeclaringType().getQualifiedName() = "org.springframework.cloud.config.server.environment.NativeEnvironmentRepository" and
      source.asParameter() = m.getAParameter()
    )
    or
    // Also capture remote flow sources
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // ClassPathResource constructor calls
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("org.springframework.core.io", "ClassPathResource") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // FileSystemResource constructor calls
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("org.springframework.core.io", "FileSystemResource") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // getResource() calls
    exists(MethodCall mc |
      mc.getMethod().hasName("getResource") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module NativeEnvFlow = TaintTracking::Global<NativeEnvConfig>;
import NativeEnvFlow::PathGraph

